  "datasets": [
    {
      "name": "f083adf4",
      "displayName": "KPI Counters",
      "queryLines": [
        "\n",
        "\n",
        "SELECT\n",
        "  (SELECT COUNT(DISTINCT customer_id) FROM primeins.gold.dim_customer) as unique_customers,\n",
        "  (SELECT COUNT(*) FROM primeins.gold.dim_policy) as active_policies,\n",
        "  (SELECT COUNT(*) FROM primeins.gold.fact_claims) as total_claims,\n",
        "  (SELECT ROUND(SUM(CASE WHEN is_rejected THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) FROM primeins.gold.fact_claims) as rejection_rate_pct,\n",
        "  (SELECT COUNT(*) FROM primeins.gold.fact_sales) as total_listings,\n",
        "  (SELECT ROUND(SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) FROM primeins.gold.fact_sales) as sell_through_pct,\n",
        "  (SELECT SUM(CASE WHEN NOT is_sold AND days_listed > 60 THEN 1 ELSE 0 END) FROM primeins.gold.fact_sales) as aging_inventory,\n",
        "  (SELECT COUNT(*) FROM primeins.gold.claim_anomaly_explanations WHERE priority = 'HIGH') as high_risk_claims\n"
      ]
    },
    {
      "name": "6e4cdf8d",
      "displayName": "Claims performance",
      "queryLines": [
        "SELECT\n",
        "  policy_csl as coverage_tier,\n",
        "  total_claims,\n",
        "  rejected_claims,\n",
        "  ROUND(rejection_rate_pct, 1) as rejection_rate_pct,\n",
        "  ROUND(avg_claim_amount, 2) as avg_claim_amount\n",
        "FROM primeins.gold.mv_rejection_rate_by_policy\n",
        "ORDER BY rejection_rate_pct DESC"
      ]
    },
    {
      "name": "8355201d",
      "displayName": "Claims by incident severity",
      "queryLines": [
        "SELECT\n",
        "  incident_severity,\n",
        "  total_claims,\n",
        "  rejected_claims,\n",
        "  ROUND(rejection_rate_pct, 1) as rejection_rate_pct,\n",
        "  ROUND(avg_claim_amount, 2) as avg_claim_amount,\n",
        "  ROUND(total_claim_value, 2) as total_claim_value\n",
        "FROM primeins.gold.mv_claims_by_severity\n",
        "ORDER BY total_claims DESC"
      ]
    },
    {
      "name": "390c4e4b",
      "displayName": "Claims by region",
      "queryLines": [
        "SELECT\n",
        "  region,\n",
        "  total_claims,\n",
        "  rejected_claims,\n",
        "  ROUND(rejection_rate_pct, 1) as rejection_rate_pct,\n",
        "  ROUND(avg_claim_amount, 2) as avg_claim_amount,\n",
        "  ROUND(total_claim_value, 2) as total_claim_value\n",
        "FROM primeins.gold.mv_claims_by_region\n",
        "ORDER BY total_claims DESC"
      ]
    },
    {
      "name": "e92e0fec",
      "displayName": "Top 10 highest value claims",
      "queryLines": [
        "SELECT\n",
        "  claim_id,\n",
        "  policy_number,\n",
        "  incident_severity,\n",
        "  incident_type,\n",
        "  ROUND(total_claim_amount, 2) as total_amount,\n",
        "  CASE WHEN is_rejected THEN 'Rejected' ELSE 'Approved' END as status,\n",
        "  incident_state,\n",
        "  incident_city\n",
        "FROM primeins.gold.fact_claims\n",
        "ORDER BY total_claim_amount DESC\n",
        "LIMIT 10"
      ]
    },
    {
      "name": "7052dcb7",
      "displayName": "Customer deduplication summary",
      "queryLines": [
        "SELECT\n",
        "  (SELECT COUNT(*) FROM primeins.silver.customers) as raw_records,\n",
        "  (SELECT COUNT(*) FROM primeins.gold.dim_customer) as unique_customers,\n",
        "  (SELECT COUNT(*) FROM primeins.silver.customers) -\n",
        "    (SELECT COUNT(*) FROM primeins.gold.dim_customer) as duplicates_resolved,\n",
        "  ROUND(\n",
        "    ((SELECT COUNT(*) FROM primeins.silver.customers) -\n",
        "     (SELECT COUNT(*) FROM primeins.gold.dim_customer)) * 100.0 /\n",
        "    (SELECT COUNT(*) FROM primeins.silver.customers), 1\n",
        "  ) as dedup_rate_pct"
      ]
    },
    {
      "name": "ed7689f0",
      "displayName": "Customers by region",
      "queryLines": [
        "SELECT\n",
        "  region,\n",
        "  COUNT(*) as customer_count,\n",
        "  ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM primeins.gold.dim_customer), 1) as pct_of_total\n",
        "FROM primeins.gold.dim_customer\n",
        "GROUP BY region\n",
        "ORDER BY customer_count DESC"
      ]
    },
    {
      "name": "bee0c678",
      "displayName": "Customer profile distribution",
      "queryLines": [
        "SELECT\n",
        "  education,\n",
        "  COUNT(*) as count\n",
        "FROM primeins.gold.dim_customer\n",
        "WHERE education IS NOT NULL\n",
        "GROUP BY education\n",
        "ORDER BY count DESC"
      ]
    },
    {
      "name": "f208cde0",
      "displayName": "Sales overview",
      "queryLines": [
        "SELECT\n",
        "  COUNT(*) as total_listings,\n",
        "  SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) as sold,\n",
        "  SUM(CASE WHEN NOT is_sold THEN 1 ELSE 0 END) as unsold,\n",
        "  ROUND(SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) as sell_through_pct,\n",
        "  ROUND(AVG(CASE WHEN is_sold THEN days_listed END), 1) as avg_days_to_sell,\n",
        "  ROUND(AVG(original_selling_price), 0) as avg_price,\n",
        "  SUM(CASE WHEN NOT is_sold AND days_listed > 60 THEN 1 ELSE 0 END) as aging_over_60_days,\n",
        "  SUM(CASE WHEN NOT is_sold AND days_listed > 90 THEN 1 ELSE 0 END) as aging_over_90_days\n",
        "FROM primeins.gold.fact_sales"
      ]
    },
    {
      "name": "8ec724e8",
      "displayName": "Unsold inventory by model and region (top 15)",
      "queryLines": [
        "SELECT\n",
        "  model,\n",
        "  region,\n",
        "  unsold_count,\n",
        "  avg_days_listed,\n",
        "  max_days_listed,\n",
        "  ROUND(avg_price, 0) as avg_price\n",
        "FROM primeins.gold.mv_unsold_inventory\n",
        "ORDER BY unsold_count DESC\n",
        "LIMIT 15"
      ]
    },
    {
      "name": "72c78bf0",
      "displayName": "Sales by region",
      "queryLines": [
        "SELECT\n",
        "  region,\n",
        "  COUNT(*) as total_listings,\n",
        "  SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) as sold,\n",
        "  SUM(CASE WHEN NOT is_sold THEN 1 ELSE 0 END) as unsold,\n",
        "  ROUND(SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) as sell_through_pct,\n",
        "  ROUND(SUM(CASE WHEN is_sold THEN original_selling_price ELSE 0 END), 0) as total_revenue\n",
        "FROM primeins.gold.fact_sales\n",
        "GROUP BY region\n",
        "ORDER BY total_listings DESC"
      ]
    }
  ],
